import React from 'react';
import Logo from './logo';

const ResultPage = ({ result, teamInfo }) => {
  const { score, totalQuestions, timeTaken, answers, questions, correctAnswers } = result;

  const formatTime = (microseconds) => {
    const seconds = Math.floor(microseconds / 1_000_000);
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes}m ${remainingSeconds}s`;
  };

  const formatMicroseconds = (microseconds) => {
    return microseconds.toLocaleString();
  };

  const percentage = Math.round((score / totalQuestions) * 100);

  const getMessage = () => {
    if (percentage >= 80) return 'Excellent work!';
    if (percentage >= 60) return 'Good job!';
    if (percentage >= 40) return 'Nice try!';
    return 'Better luck next time!';
  };

  const getScoreColor = () => {
    if (percentage >= 80) return '#00aa00';
    if (percentage >= 60) return '#ffaa00';
    return '#ff0000';
  };

  return (
    <div style={{
      minHeight: '100vh',
      backgroundColor: '#ffffff',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      padding: '20px'
    }}>
      <div style={{
        width: '100%',
        maxWidth: '800px',
        padding: '30px'
      }}>
        {/* Header with Logo */}
        <div style={{ 
          textAlign: 'center', 
          marginBottom: '40px',
          borderBottom: '1px solid #e5e5e5',
          paddingBottom: '20px'
        }}>
          <div style={{ display: 'inline-block' }}>
            <Logo size={50} />
          </div>
          <h1 style={{ 
            fontSize: '36px', 
            marginTop: '20px',
            marginBottom: '10px', 
            color: '#1a202c',
            fontWeight: '700'
          }}>
            Quiz Complete!
          </h1>

          <p style={{ 
            color: '#4a5568', 
            marginBottom: '20px', 
            fontSize: '18px',
            fontWeight: '500'
          }}>
            {teamInfo.teamName}
          </p>
        </div>

        {/* Score Section */}
        <div style={{ textAlign: 'center', marginBottom: '40px' }}>
          <div style={{ 
            backgroundColor: '#f8f9fa',
            padding: '30px',
            borderRadius: '12px',
            marginBottom: '20px'
          }}>
            <div style={{ 
              fontSize: '64px', 
              fontWeight: '700', 
              color: getScoreColor(),
              marginBottom: '10px'
            }}>
              {score}/{totalQuestions}
            </div>

            <div style={{ 
              fontSize: '24px', 
              color: '#2d3748',
              marginBottom: '15px',
              fontWeight: '600'
            }}>
              {percentage}%
            </div>

            <div style={{ 
              fontSize: '18px', 
              color: '#4a5568',
              marginBottom: '20px'
            }}>
              {getMessage()}
            </div>

            <div style={{ 
              fontSize: '14px', 
              color: '#718096'
            }}>
              Time taken: {formatTime(timeTaken)}
              <div style={{ fontSize: '12px', marginTop: '5px' }}>
                ({formatMicroseconds(timeTaken)} microseconds)
              </div>
            </div>
          </div>
        </div>

        {/* Answer Review */}
        <h2 style={{ 
          fontSize: '24px', 
          marginBottom: '20px',
          color: '#1a202c',
          fontWeight: '600',
          textAlign: 'center'
        }}>
          Answer Review
        </h2>

        <div style={{
          display: 'flex',
          flexDirection: 'column',
          gap: '15px',
          marginBottom: '30px'
        }}>
          {questions.map((question, index) => {
            const userAnswer = answers[question.id];
            const correctAnswer = correctAnswers[question.id];
            const isCorrect = userAnswer === correctAnswer;

            return (
              <div
                key={question.id}
                style={{
                  padding: '20px',
                  backgroundColor: '#f8f9fa',
                  borderRadius: '8px',
                  borderLeft: `4px solid ${isCorrect ? '#00aa00' : '#ff0000'}`
                }}
              >
                <div style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  marginBottom: '10px'
                }}>
                  <span style={{
                    fontSize: '16px',
                    fontWeight: '600',
                    color: '#1a202c'
                  }}>
                    Question {index + 1}
                  </span>
                  <span style={{
                    fontSize: '14px',
                    padding: '4px 8px',
                    borderRadius: '4px',
                    backgroundColor: isCorrect ? '#e6f7e6' : '#ffe6e6',
                    color: isCorrect ? '#00aa00' : '#ff0000',
                    fontWeight: '600'
                  }}>
                    {isCorrect ? '✓ Correct' : '✗ Incorrect'}
                  </span>
                </div>

                <p style={{
                  fontSize: '15px',
                  color: '#2d3748',
                  marginBottom: '15px',
                  fontWeight: '500'
                }}>
                  {question.question}
                </p>

                <div style={{
                  display: 'grid',
                  gridTemplateColumns: '1fr 1fr',
                  gap: '15px',
                  fontSize: '14px'
                }}>
                  <div style={{
                    padding: '10px',
                    backgroundColor: '#ffffff',
                    borderRadius: '4px'
                  }}>
                    <span style={{ color: '#718096' }}>Your answer: </span>
                    <span style={{ 
                      color: isCorrect ? '#00aa00' : '#ff0000',
                      fontWeight: '600'
                    }}>
                      {userAnswer || 'Not answered'}
                    </span>
                  </div>

                  <div style={{
                    padding: '10px',
                    backgroundColor: '#ffffff',
                    borderRadius: '4px'
                  }}>
                    <span style={{ color: '#718096' }}>Correct answer: </span>
                    <span style={{ color: '#00aa00', fontWeight: '600' }}>
                      {correctAnswer}
                    </span>
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Score Summary */}
        <div style={{
          backgroundColor: '#f8f9fa',
          padding: '20px',
          borderRadius: '8px',
          marginBottom: '20px',
          textAlign: 'center'
        }}>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(3, 1fr)',
            gap: '15px'
          }}>
            <div>
              <div style={{ fontSize: '14px', color: '#718096' }}>Correct</div>
              <div style={{ fontSize: '24px', fontWeight: '600', color: '#00aa00' }}>{score}</div>
            </div>
            <div>
              <div style={{ fontSize: '14px', color: '#718096' }}>Incorrect</div>
              <div style={{ fontSize: '24px', fontWeight: '600', color: '#ff0000' }}>{totalQuestions - score}</div>
            </div>
            <div>
              <div style={{ fontSize: '14px', color: '#718096' }}>Accuracy</div>
              <div style={{ fontSize: '24px', fontWeight: '600', color: '#1a202c' }}>{percentage}%</div>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div style={{ 
          textAlign: 'center',
          padding: '20px',
          borderTop: '1px solid #e5e5e5',
          color: '#6c757d',
          fontSize: '14px'
        }}>
          Thank you for participating with Bulls & Bears!
        </div>
      </div>
    </div>
  );
};

export default ResultPage;
